#include <bits/stdc++.h>
using namespace std;
const int maxn=1e4+5;
int n,a[maxn],ans,s[maxn],u[maxn];
bool cheek() {
	fill(u,u+5+n,0);
	for(int i=1; i<=n; i++) {
		if(s[i]==1) {
			u[i-1]++;
			u[i]++;
			u[i+1]++;
		}
	}
	for(int i=1; i<=n; i++) {
		if(u[i]!=a[i]) {
			return 0;
		}
	}
	return 1;
}
void dfs(int i) {
	if(i>=3&&a[i-2]-s[i-3]-s[i-2]-s[i-1]!=0) return;
	if(i>n) {
		if(cheek())
			ans++;
		return;
	}
	if(s[i-1]==-1&&s[i-2]==-1&&a[i-1]!=3) {
		s[i]=0;
		dfs(i+1);
	}
	s[i]=1;
	dfs(i+1);
	s[i]=0;
	dfs(i+1);
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	dfs(1);
	cout<<ans;
	return 0;
}
